#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2026/5/11# @Author : cyq# @File : map_data# @Software: PyCharm# @Desc:from sqlalchemy import Column, Integer, Stringfrom app.model.basic import BaseModelclass TestCaseStatus(BaseModel):    __tablename__ = 'map_test_case_status'    status_label = Column(String(20), nullable=False, comment="类型名")    status_value = Column(String(20), nullable=False, comment="类型")    def __repr__(self):        return f"<TestCaseStatus status: {self.status_label}>"class TestCaseLevel(BaseModel):    __tablename__ = 'map_test_case_level'    level_label = Column(String(20), nullable=False, comment="级别名")    level_value = Column(String(20), nullable=False, comment="级别中")    def __repr__(self):        return f"<TestCaseLevel status: {self.level_label}>"class TestCaseProgress(BaseModel):    __tablename__ = 'map_test_case_progress'    progress_label = Column(String(20), nullable=False,comment="进度")    progress_value = Column(Integer, nullable=False,comment="进度")    def __repr__(self):        return f"<TestCaseProgress progress: {self.progress_label}>"